// src/pages/FarmEditPage.js
import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import '../Dashboard.css'; // Sử dụng CSS chung hoặc CSS của form

function FarmEditPage() {
  const { farmId } = useParams(); // Lấy farmId từ URL
  const navigate = useNavigate();
  const token = localStorage.getItem('token');
  const [farmData, setFarmData] = useState({
    tenCoSo: '',
    tinh: '',
    huyen: '',
    xa: '',
    chuTrai: '', // Trường Chủ trại
    soDienThoai: '',
    // Thêm các trường khác của farm nếu cần
  });
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [message, setMessage] = useState('');

  useEffect(() => {
    const fetchFarm = async () => {
      try {
        setLoading(true);
        const response = await axios.get(`http://localhost:10000/api/farms/${farmId}`, {
          headers: { Authorization: `Bearer ${token}` }
        });
        setFarmData(response.data);
      } catch (err) {
        setError('Không thể tải thông tin cơ sở nuôi.');
        console.error('Lỗi khi tải thông tin farm:', err);
      } finally {
        setLoading(false);
      }
    };
    if (farmId) {
      fetchFarm();
    }
  }, [farmId, token]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFarmData(prevData => ({
      ...prevData,
      [name]: value
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      await axios.put(`http://localhost:10000/api/farms/${farmId}`, farmData, {
        headers: { Authorization: `Bearer ${token}` }
      });
      setMessage('Cập nhật thông tin cơ sở nuôi thành công!');
      // Điều hướng về trang danh sách sau khi cập nhật
      navigate('/admin/farms'); // Hoặc '/register-manage/sub2' nếu đó là đường dẫn chính
    } catch (err) {
      setError('Lỗi khi cập nhật thông tin cơ sở nuôi.');
      console.error('Lỗi khi cập nhật farm:', err);
    }
  };

  if (loading) return <p>Đang tải thông tin cơ sở...</p>;
  if (error) return <p style={{ color: 'red' }}>Lỗi: {error}</p>;

  return (
    <div className="main-content"> {/* Đảm bảo class này phù hợp với layout của bạn */}
      <h2>✏️ Chỉnh sửa Cơ sở nuôi</h2>

      {message && <p style={{ color: 'green' }}>{message}</p>}

      <form onSubmit={handleSubmit} className="form-container">
        <div className="form-group">
          <label>Tên cơ sở:</label>
          <input
            type="text"
            name="tenCoSo"
            value={farmData.tenCoSo}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Tỉnh:</label>
          <input
            type="text"
            name="tinh"
            value={farmData.tinh}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Huyện:</label>
          <input
            type="text"
            name="huyen"
            value={farmData.huyen}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Xã:</label>
          <input
            type="text"
            name="xa"
            value={farmData.xa}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Chủ trại:</label>
          <input
            type="text"
            name="chuTrai"
            value={farmData.chuTrai}
            onChange={handleChange}
            required
          />
        </div>
        <div className="form-group">
          <label>Số điện thoại:</label>
          <input
            type="text"
            name="soDienThoai"
            value={farmData.soDienThoai}
            onChange={handleChange}
          />
        </div>
        {/* Thêm các trường khác tương ứng với mô hình dữ liệu farm của bạn */}
        <button type="submit" className="submit-button">Cập nhật</button>
      </form>
    </div>
  );
}

export default FarmEditPage;
